import axios from 'axios';

// 创建axios实例
const apiClient = axios.create({
  baseURL: process.env.VUE_APP_API_URL || 'http://localhost:8080/api',
  timeout: 10000,
  withCredentials: true,
  headers: {
    'Accept': 'application/json',
    'Content-Type': 'application/json'
  }
});

// 请求拦截器
apiClient.interceptors.request.use(
  config => {
    // 从localStorage获取token
    const userStr = localStorage.getItem('user');
    if (userStr) {
      try {
        const user = JSON.parse(userStr);
        const token = user.accessToken || user.token;
        if (token) {
          // 在请求头中添加token
          config.headers['Authorization'] = `Bearer ${token}`;
          console.log('API Client: 添加认证头', `Bearer ${token.substring(0, 10)}...`);
        }
      } catch (e) {
        console.error('API Client: 解析用户信息失败', e);
      }
    }
    
    console.log('API Client 请求:', {
      url: config.url,
      method: config.method.toUpperCase(),
      headers: config.headers
    });
    
    return config;
  },
  error => {
    console.error('API Client 请求错误:', error);
    return Promise.reject(error);
  }
);

// 响应拦截器
apiClient.interceptors.response.use(
  response => {
    console.log('API Client 响应成功:', response.status, response.config.url);
    return response.data;
  },
  error => {
    console.error('API Client 响应错误:', 
      error.response?.status || 'Unknown',
      error.config?.url || 'Unknown',
      error.response?.data || error.message);
    
    if (error.response && error.response.status === 401) {
      // 未授权，清除本地存储中的用户信息
      localStorage.removeItem('user');
      console.warn('API Client: 收到401响应，已清除用户信息');
      
      // 如果不在登录页面，重定向到登录页面
      if (window.location.pathname !== '/login') {
        window.location.href = '/login?redirect=' + encodeURIComponent(window.location.pathname);
      }
    }
    
    return Promise.reject(error);
  }
);

export default apiClient;
